 24→			name: "Right triangle",
 25→			paX:  0, paY: 0,
 26→			pbX: 0, pbY: 3,
 27→			pcX: 4, pcY: 0,
 28→			expected: 6.0,
 29→		},
 30→		{
 31→			name: "Collinear points (zero area)",
 32→			paX:  0, paY: 0,
 33→			pbX: 1, pbY: 1,
 34→			pcX: 2, pcY: 2,
 35→			expected: 0.0,
 36→		},
 37→		{
 38→			name: "Negative coordinates",
