 40→			pbX: -1, pbY: 2,
 41→			pcX: 3, pcY: -1,
 42→			expected: 6.0,
 43→		},
 44→	}
 45→
 46→	for _, tt := range tests {
 47→		t.Run(tt.name, func(t *testing.T) {
 48→			result := calculateTriangleArea(tt.paX, tt.paY, tt.pbX, tt.pbY, tt.pcX, tt.pcY)
 49→			if math.Abs(result-tt.expected) > 1e-10 {
 50→				t.Errorf("calculateTriangleArea() = %v, want %v", result, tt.expected)
 51→			}
 52→		})
 53→	}
 54→}
