 92→			xStart:    0,
 93→			expectedX: 0.5,
 94→			expectNaN: true,
 95→		},
 96→	}
 97→
 98→	for _, tt := range tests {
 99→		t.Run(tt.name, func(t *testing.T) {
100→			avgX, avgY := calculateAverageDataPoint(tt.points, tt.xStart)
