108→			} else {
109→				if math.Abs(float64(avgY-tt.expectedY)) > 1e-10 {
110→					t.Errorf("calculateAverageDataPoint() avgY = %v, want %v", avgY, tt.expectedY)
111→				}
112→			}
113→		})
114→	}
115→}
