153→			name:         "Zero old frequency",
154→			data:         makeTestData(200, 1.0),
155→			oldFrequency: 0,
156→			newFrequency: 2,
157→			expectedLen:  200,
158→			expectedFreq: 0,
159→			expectError:  false,
160→		},
