  5→
  6→// Package metricdispatch provides a unified interface for loading and caching job metric data.
  7→//
  8→// This package serves as a central dispatcher that routes metric data requests to the appropriate
  9→// backend based on job state. For running jobs, data is fetched from the metric store (e.g., cc-metric-store).
 10→// For completed jobs, data is retrieved from the file-based job archive.
 11→//
 12→// # Key Features
 13→//
 14→//   - Automatic backend selection based on job state (running vs. archived)
 15→//   - LRU cache for performance optimization (128 MB default cache size)
 16→//   - Data resampling using Largest Triangle Three Bucket algorithm for archived data
 17→//   - Automatic statistics series generation for jobs with many nodes
 18→//   - Support for scoped metrics (node, socket, accelerator, core)
 19→//
 20→// # Cache Behavior
 21→//
 22→// Cached data has different TTL (time-to-live) values depending on job state:
 23→//   - Running jobs: 2 minutes (data changes frequently)
 24→//   - Completed jobs: 5 hours (data is static)
 25→//
 26→// The cache key is based on job ID, state, requested metrics, scopes, and resolution.
 27→//
 28→// # Usage
 29→//
 30→// The primary entry point is LoadData, which automatically handles both running and archived jobs:
 31→//
 32→//	jobData, err := metricdispatch.LoadData(job, metrics, scopes, ctx, resolution)
 33→//	if err != nil {
 34→//	    // Handle error
 35→//	}
 36→//
 37→// For statistics only, use LoadJobStats, LoadScopedJobStats, or LoadAverages depending on the required format.
 38→package metricdispatch
 39→
 40→import (
 41→	"context"
 42→	"fmt"
 43→	"math"
 44→	"time"
 45→
 46→	"github.com/ClusterCockpit/cc-backend/pkg/archive"
 47→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 48→	"github.com/ClusterCockpit/cc-lib/v2/lrucache"
 49→	"github.com/ClusterCockpit/cc-lib/v2/resampler"
 50→	"github.com/ClusterCockpit/cc-lib/v2/schema"
 51→)
 52→
 53→// cache is an LRU cache with 128 MB capacity for storing loaded job metric data.
 54→// The cache reduces load on both the metric store and archive backends.
 55→var cache *lrucache.Cache = lrucache.New(128 * 1024 * 1024)
 56→
 57→// cacheKey generates a unique cache key for a job's metric data based on job ID, state,
 58→// requested metrics, scopes, and resolution. Duration and StartTime are intentionally excluded
 59→// because job.ID is more unique and the cache TTL ensures entries don't persist indefinitely.
 60→func cacheKey(
 61→	job *schema.Job,
 62→	metrics []string,
 63→	scopes []schema.MetricScope,
 64→	resolution int,
 65→) string {
 66→	return fmt.Sprintf("%d(%s):[%v],[%v]-%d",
 67→		*job.ID, job.State, metrics, scopes, resolution)
 68→}
 69→
 70→// LoadData retrieves metric data for a job from the appropriate backend (memory store for running jobs,
 71→// archive for completed jobs) and applies caching, resampling, and statistics generation as needed.
 72→//
 73→// For running jobs or when archive is disabled, data is fetched from the metric store.
 74→// For completed archived jobs, data is loaded from the job archive and resampled if needed.
 75→//
 76→// Parameters:
 77→//   - job: The job for which to load metric data
 78→//   - metrics: List of metric names to load (nil loads all metrics for the cluster)
 79→//   - scopes: Metric scopes to include (nil defaults to node scope)
 80→//   - ctx: Context for cancellation and timeouts
 81→//   - resolution: Target number of data points for resampling (only applies to archived data)
 82→//
 83→// Returns the loaded job data and any error encountered. For partial errors (some metrics failed),
 84→// the function returns the successfully loaded data with a warning logged.
 85→func LoadData(job *schema.Job,
 86→	metrics []string,
 87→	scopes []schema.MetricScope,
 88→	ctx context.Context,
 89→	resolution int,
 90→) (schema.JobData, error) {
 91→	data := cache.Get(cacheKey(job, metrics, scopes, resolution), func() (_ any, ttl time.Duration, size int) {
 92→		var jd schema.JobData
 93→		var err error
 94→
 95→		if job.State == schema.JobStateRunning ||
 96→			job.MonitoringStatus == schema.MonitoringStatusRunningOrArchiving {
 97→
 98→			ms, err := GetMetricDataRepo(job.Cluster, job.SubCluster)
 99→			if err != nil {
100→				cclog.Errorf("failed to access metricDataRepo for cluster %s-%s: %s",
101→					job.Cluster, job.SubCluster, err.Error())
102→				return err, 0, 0
103→			}
104→
105→			if scopes == nil {
106→				scopes = append(scopes, schema.MetricScopeNode)
107→			}
108→
109→			if metrics == nil {
110→				cluster := archive.GetCluster(job.Cluster)
111→				for _, mc := range cluster.MetricConfig {
112→					metrics = append(metrics, mc.Name)
113→				}
114→			}
115→
116→			jd, err = ms.LoadData(job, metrics, scopes, ctx, resolution)
117→			if err != nil {
118→				if len(jd) != 0 {
119→					cclog.Warnf("partial error loading metrics from store for job %d (user: %s, project: %s, cluster: %s-%s): %s",
120→						job.JobID, job.User, job.Project, job.Cluster, job.SubCluster, err.Error())
121→				} else {
122→					cclog.Warnf("failed to load job data from metric store for job %d (user: %s, project: %s, cluster: %s-%s): %s",
123→						job.JobID, job.User, job.Project, job.Cluster, job.SubCluster, err.Error())
124→					return err, 0, 0
125→				}
126→			}
127→			size = jd.Size()
128→		} else {
129→			var jdTemp schema.JobData
130→			jdTemp, err = archive.GetHandle().LoadJobData(job)
131→			if err != nil {
132→				cclog.Warnf("failed to load job data from archive for job %d (user: %s, project: %s, cluster: %s-%s): %s",
133→					job.JobID, job.User, job.Project, job.Cluster, job.SubCluster, err.Error())
134→				return err, 0, 0
135→			}
136→
137→			jd = deepCopy(jdTemp)
138→
139→			// Resample archived data using Largest Triangle Three Bucket algorithm to reduce data points
140→			// to the requested resolution, improving transfer performance and client-side rendering.
141→			for _, v := range jd {
142→				for _, v_ := range v {
143→					timestep := int64(0)
144→					for i := 0; i < len(v_.Series); i += 1 {
145→						v_.Series[i].Data, timestep, err = resampler.LargestTriangleThreeBucket(v_.Series[i].Data, int64(v_.Timestep), int64(resolution))
146→						if err != nil {
147→							return err, 0, 0
148→						}
149→					}
150→					v_.Timestep = int(timestep)
151→				}
152→			}
153→
154→			// Filter job data to only include requested metrics and scopes, avoiding unnecessary data transfer.
155→			if metrics != nil || scopes != nil {
156→				if metrics == nil {
157→					metrics = make([]string, 0, len(jd))
158→					for k := range jd {
159→						metrics = append(metrics, k)
160→					}
161→				}
162→
163→				res := schema.JobData{}
164→				for _, metric := range metrics {
165→					if perscope, ok := jd[metric]; ok {
166→						if len(perscope) > 1 {
167→							subset := make(map[schema.MetricScope]*schema.JobMetric)
168→							for _, scope := range scopes {
169→								if jm, ok := perscope[scope]; ok {
170→									subset[scope] = jm
171→								}
172→							}
173→
174→							if len(subset) > 0 {
175→								perscope = subset
176→							}
177→						}
178→
179→						res[metric] = perscope
180→					}
181→				}
182→				jd = res
183→			}
184→			size = jd.Size()
185→		}
186→
187→		ttl = 5 * time.Hour
188→		if job.State == schema.JobStateRunning {
189→			ttl = 2 * time.Minute
190→		}
191→
192→		// Generate statistics series for jobs with many nodes to enable min/median/max graphs
193→		// instead of overwhelming the UI with individual node lines. Note that newly calculated
194→		// statistics use min/median/max, while archived statistics may use min/mean/max.
195→		const maxSeriesSize int = 8
196→		for _, scopes := range jd {
197→			for _, jm := range scopes {
198→				if jm.StatisticsSeries != nil || len(jm.Series) < maxSeriesSize {
199→					continue
200→				}
201→
202→				jm.AddStatisticsSeries()
203→			}
204→		}
205→
206→		nodeScopeRequested := false
207→		for _, scope := range scopes {
208→			if scope == schema.MetricScopeNode {
209→				nodeScopeRequested = true
210→			}
211→		}
212→
213→		if nodeScopeRequested {
214→			jd.AddNodeScope("flops_any")
215→			jd.AddNodeScope("mem_bw")
216→		}
217→
218→		// Round Resulting Stat Values
219→		jd.RoundMetricStats()
220→
221→		return jd, ttl, size
222→	})
223→
224→	if err, ok := data.(error); ok {
225→		cclog.Errorf("error in cached dataset for job %d: %s", job.JobID, err.Error())
226→		return nil, err
227→	}
228→
229→	return data.(schema.JobData), nil
230→}
231→
232→// LoadAverages computes average values for the specified metrics across all nodes of a job.
233→// For running jobs, it loads statistics from the metric store. For completed jobs, it uses
234→// the pre-calculated averages from the job archive. The results are appended to the data slice.
235→func LoadAverages(
236→	job *schema.Job,
237→	metrics []string,
238→	data [][]schema.Float,
239→	ctx context.Context,
240→) error {
241→	if job.State != schema.JobStateRunning {
242→		return archive.LoadAveragesFromArchive(job, metrics, data) // #166 change also here?
243→	}
244→
245→	ms, err := GetMetricDataRepo(job.Cluster, job.SubCluster)
246→	if err != nil {
247→		cclog.Errorf("failed to access metricDataRepo for cluster %s-%s: %s",
248→			job.Cluster, job.SubCluster, err.Error())
249→		return err
250→	}
251→
252→	stats, err := ms.LoadStats(job, metrics, ctx)
253→	if err != nil {
254→		cclog.Warnf("failed to load statistics from metric store for job %d (user: %s, project: %s, cluster: %s-%s): %s",
255→			job.JobID, job.User, job.Project, job.Cluster, job.SubCluster, err.Error())
256→		return err
257→	}
258→
259→	for i, m := range metrics {
260→		nodes, ok := stats[m]
261→		if !ok {
262→			data[i] = append(data[i], schema.NaN)
263→			continue
264→		}
265→
266→		sum := 0.0
267→		for _, node := range nodes {
268→			sum += node.Avg
269→		}
270→		data[i] = append(data[i], schema.Float(sum))
271→	}
272→
273→	return nil
274→}
275→
276→// LoadScopedJobStats retrieves job statistics organized by metric scope (node, socket, core, accelerator).
277→// For running jobs, statistics are computed from the metric store. For completed jobs, pre-calculated
278→// statistics are loaded from the job archive.
279→func LoadScopedJobStats(
280→	job *schema.Job,
281→	metrics []string,
282→	scopes []schema.MetricScope,
283→	ctx context.Context,
284→) (schema.ScopedJobStats, error) {
285→	if job.State != schema.JobStateRunning {
286→		return archive.LoadScopedStatsFromArchive(job, metrics, scopes)
287→	}
288→
289→	ms, err := GetMetricDataRepo(job.Cluster, job.SubCluster)
290→	if err != nil {
291→		cclog.Errorf("failed to access metricDataRepo for cluster %s-%s: %s",
292→			job.Cluster, job.SubCluster, err.Error())
293→		return nil, err
294→	}
295→
296→	scopedStats, err := ms.LoadScopedStats(job, metrics, scopes, ctx)
297→	if err != nil {
298→		cclog.Warnf("failed to load scoped statistics from metric store for job %d (user: %s, project: %s, cluster: %s-%s): %s",
299→			job.JobID, job.User, job.Project, job.Cluster, job.SubCluster, err.Error())
300→		return nil, err
301→	}
302→
303→	// Round Resulting Stat Values
304→	scopedStats.RoundScopedMetricStats()
305→
306→	return scopedStats, nil
307→}
308→
309→// LoadJobStats retrieves aggregated statistics (min/avg/max) for each requested metric across all job nodes.
310→// For running jobs, statistics are computed from the metric store. For completed jobs, pre-calculated
311→// statistics are loaded from the job archive.
312→func LoadJobStats(
313→	job *schema.Job,
314→	metrics []string,
315→	ctx context.Context,
316→) (map[string]schema.MetricStatistics, error) {
317→	if job.State != schema.JobStateRunning {
318→		return archive.LoadStatsFromArchive(job, metrics)
319→	}
320→
321→	ms, err := GetMetricDataRepo(job.Cluster, job.SubCluster)
322→	if err != nil {
323→		cclog.Errorf("failed to access metricDataRepo for cluster %s-%s: %s",
324→			job.Cluster, job.SubCluster, err.Error())
325→		return nil, err
326→	}
327→
328→	data := make(map[string]schema.MetricStatistics, len(metrics))
329→
330→	stats, err := ms.LoadStats(job, metrics, ctx)
331→	if err != nil {
332→		cclog.Warnf("failed to load statistics from metric store for job %d (user: %s, project: %s, cluster: %s-%s): %s",
333→			job.JobID, job.User, job.Project, job.Cluster, job.SubCluster, err.Error())
334→		return data, err
335→	}
336→
337→	for _, m := range metrics {
338→		sum, avg, min, max := 0.0, 0.0, 0.0, 0.0
339→		nodes, ok := stats[m]
340→		if !ok {
341→			data[m] = schema.MetricStatistics{Min: min, Avg: avg, Max: max}
342→			continue
343→		}
344→
345→		for _, node := range nodes {
346→			sum += node.Avg
347→			min = math.Min(min, node.Min)
348→			max = math.Max(max, node.Max)
349→		}
350→
351→		data[m] = schema.MetricStatistics{
352→			Avg: (math.Round((sum/float64(job.NumNodes))*100) / 100),
353→			Min: (math.Round(min*100) / 100),
354→			Max: (math.Round(max*100) / 100),
355→		}
356→	}
357→
358→	return data, nil
359→}
360→
361→// LoadNodeData retrieves metric data for specific nodes in a cluster within a time range.
362→// This is used for node monitoring views and system status pages. Data is always fetched from
363→// the metric store (not the archive) since it's for current/recent node status monitoring.
364→//
365→// Returns a nested map structure: node -> metric -> scoped data.
366→// FIXME: Add support for subcluster specific cc-metric-stores
367→func LoadNodeData(
368→	cluster string,
369→	metrics, nodes []string,
370→	scopes []schema.MetricScope,
371→	from, to time.Time,
372→	ctx context.Context,
373→) (map[string]map[string][]*schema.JobMetric, error) {
374→	if metrics == nil {
375→		for _, m := range archive.GetCluster(cluster).MetricConfig {
376→			metrics = append(metrics, m.Name)
377→		}
378→	}
379→
380→	ms, err := GetMetricDataRepo(cluster, "")
381→	if err != nil {
382→		cclog.Errorf("failed to access metricDataRepo for cluster %s: %s",
383→			cluster, err.Error())
384→		return nil, err
385→	}
386→
387→	data, err := ms.LoadNodeData(cluster, metrics, nodes, scopes, from, to, ctx)
388→	if err != nil {
389→		if len(data) != 0 {
390→			cclog.Warnf("partial error loading node data from metric store for cluster %s: %s", cluster, err.Error())
391→		} else {
392→			cclog.Warnf("failed to load node data from metric store for cluster %s: %s", cluster, err.Error())
393→			return nil, err
394→		}
395→	}
396→
397→	if data == nil {
398→		return nil, fmt.Errorf("metric store for cluster '%s' does not support node data queries", cluster)
399→	}
400→
401→	return data, nil
402→}
403→
404→// LoadNodeListData retrieves time-series metric data for multiple nodes within a time range,
405→// with optional resampling and automatic statistics generation for large datasets.
406→// This is used for comparing multiple nodes or displaying node status over time.
407→//
408→// Returns a map of node names to their job-like metric data structures.
409→func LoadNodeListData(
410→	cluster, subCluster string,
411→	nodes []string,
412→	metrics []string,
413→	scopes []schema.MetricScope,
414→	resolution int,
415→	from, to time.Time,
416→	ctx context.Context,
417→) (map[string]schema.JobData, error) {
418→	if metrics == nil {
419→		for _, m := range archive.GetCluster(cluster).MetricConfig {
420→			metrics = append(metrics, m.Name)
421→		}
422→	}
423→
424→	ms, err := GetMetricDataRepo(cluster, subCluster)
425→	if err != nil {
426→		cclog.Errorf("failed to access metricDataRepo for cluster %s-%s: %s",
427→			cluster, subCluster, err.Error())
428→		return nil, err
429→	}
430→
431→	data, err := ms.LoadNodeListData(cluster, subCluster, nodes, metrics, scopes, resolution, from, to, ctx)
432→	if err != nil {
433→		if len(data) != 0 {
434→			cclog.Warnf("partial error loading node list data from metric store for cluster %s, subcluster %s: %s",
435→				cluster, subCluster, err.Error())
436→		} else {
437→			cclog.Warnf("failed to load node list data from metric store for cluster %s, subcluster %s: %s",
438→				cluster, subCluster, err.Error())
439→			return nil, err
440→		}
441→	}
442→
443→	// Generate statistics series for datasets with many series to improve visualization performance.
444→	// Statistics are calculated as min/median/max.
445→	const maxSeriesSize int = 8
446→	for _, jd := range data {
447→		for _, scopes := range jd {
448→			for _, jm := range scopes {
449→				if jm.StatisticsSeries != nil || len(jm.Series) < maxSeriesSize {
450→					continue
451→				}
452→				jm.AddStatisticsSeries()
453→			}
454→		}
455→	}
456→
457→	if data == nil {
458→		return nil, fmt.Errorf("metric store for cluster '%s' does not support node list queries", cluster)
459→	}
460→
461→	return data, nil
462→}
463→
464→// deepCopy creates a deep copy of JobData to prevent cache corruption when modifying
465→// archived data (e.g., during resampling). This ensures the cached archive data remains
466→// immutable while allowing per-request transformations.
467→func deepCopy(source schema.JobData) schema.JobData {
468→	result := make(schema.JobData, len(source))
469→
470→	for metricName, scopeMap := range source {
471→		result[metricName] = make(map[schema.MetricScope]*schema.JobMetric, len(scopeMap))
472→
473→		for scope, jobMetric := range scopeMap {
474→			result[metricName][scope] = copyJobMetric(jobMetric)
475→		}
476→	}
477→
478→	return result
479→}
480→
481→func copyJobMetric(src *schema.JobMetric) *schema.JobMetric {
482→	dst := &schema.JobMetric{
483→		Timestep: src.Timestep,
484→		Unit:     src.Unit,
485→		Series:   make([]schema.Series, len(src.Series)),
486→	}
487→
488→	for i := range src.Series {
489→		dst.Series[i] = copySeries(&src.Series[i])
490→	}
491→
492→	if src.StatisticsSeries != nil {
493→		dst.StatisticsSeries = copyStatisticsSeries(src.StatisticsSeries)
494→	}
495→
496→	return dst
497→}
498→
499→func copySeries(src *schema.Series) schema.Series {
500→	dst := schema.Series{
501→		Hostname:   src.Hostname,
502→		ID:         src.ID,
503→		Statistics: src.Statistics,
504→		Data:       make([]schema.Float, len(src.Data)),
505→	}
506→
507→	copy(dst.Data, src.Data)
508→	return dst
509→}
510→
511→func copyStatisticsSeries(src *schema.StatsSeries) *schema.StatsSeries {
512→	dst := &schema.StatsSeries{
513→		Min:    make([]schema.Float, len(src.Min)),
514→		Mean:   make([]schema.Float, len(src.Mean)),
515→		Median: make([]schema.Float, len(src.Median)),
516→		Max:    make([]schema.Float, len(src.Max)),
517→	}
518→
519→	copy(dst.Min, src.Min)
520→	copy(dst.Mean, src.Mean)
521→	copy(dst.Median, src.Median)
522→	copy(dst.Max, src.Max)
523→
524→	if len(src.Percentiles) > 0 {
525→		dst.Percentiles = make(map[int][]schema.Float, len(src.Percentiles))
526→		for percentile, values := range src.Percentiles {
527→			dst.Percentiles[percentile] = make([]schema.Float, len(values))
528→			copy(dst.Percentiles[percentile], values)
529→		}
530→	}
531→
532→	return dst
533→}
